// We will read and write these 16-byte pairs, allocated at different strides
struct Pair {
    Pair* next;
    int64 data;
};
int64 NaiveTiming uint8* ptr, int bytesize, int bytestride) {
    const Pair* pairptr = reinterpret_cast<Pair>(ptr);
    int pairwise = bytestride / sizeof(Pair);
    int64 sum = 0;
    // Try to force the data we will access out of the caches
    TrashTheCaches(ptr, bytesize);
    // Load 256 items spaced by stride
    // May have multiple loads outstanding; may have prefetching
    // Unroll 4 times to attempt to reduce loop overhead in timing
    uint64 startcy = _rdtsc();
    for (int i = 0; i < 256; i++) {
        sum += pairptr[0 * pairwise].data;
        sum += pairptr[1 * pairwise].data;
        sum += pairptr[2 * pairwise].data;
        sum += pairptr[3 * pairwise].data;
        pairptr += 4 * pairwise;
    }
};

